int main (int argc, char* argv[]) {
    if (argc > 1) {
        print_level = std::atoi(argv[1]);
    }
    if (argc > 2) {
        g_lib_path = argv[2];
    }
    if (argc > 3) {
        g_data_path = argv[3];
    }

    const int driver_err = run_loader_driver();
    summarize_test_results();

    printf("=======================================================\n");
    printf(" TESTING RUNTIME STATIC LOADER: TOTAL FAILURES: %d/%d\n", total_test_fails, total_tests_run);
    printf("=======================================================\n");

    if (driver_err != 0) {
        return driver_err;
    }
    return total_test_fails;
}

